class Solution(object):
    def smallestBeautifulString(self, s, k):
        """
        :type s: str
        :type k: int
        :rtype: str
        """
        s = list(s)
        n = len(s)

        # Find the rightmost position to increment
        for i in range(n - 1, -1, -1):
            # Try incrementing character at position i
            for c in range(ord(s[i]) + 1, ord('a') + k):
                s[i] = chr(c)

                # Check if it creates palindrome at position i and i-1
                if i >= 1 and s[i] == s[i-1]:
                    continue

                # Check if it creates palindrome at position i and i-2
                if i >= 2 and s[i] == s[i-2]:
                    continue

                # Valid, now fill rest greedily
                valid = True
                for j in range(i + 1, n):
                    # Try smallest character
                    found = False
                    for c2 in range(ord('a'), ord('a') + k):
                        ch = chr(c2)
                        # Check no palindrome of length 2 or 3
                        if j >= 1 and ch == s[j-1]:
                            continue
                        if j >= 2 and ch == s[j-2]:
                            continue
                        s[j] = ch
                        found = True
                        break

                    if not found:
                        valid = False
                        break

                if valid:
                    return ''.join(s)

        return ""
